    /// <summary>
    /// Formats a collection using an object-returning formatter.
    /// </summary>
    public string Humanize<T>(IEnumerable<T> collection, Func<T, object?> objectFormatter) =>
        Humanize(collection, objectFormatter, DefaultSeparator);

    /// <inheritdoc />
    public virtual string Humanize<T>(IEnumerable<T> collection, string separator) =>
        Humanize(collection, o => o?.ToString(), separator);

    /// <summary>
    /// Core formatting method that converts a collection to a human-readable string.
    /// </summary>
    public virtual string Humanize<T>(
        IEnumerable<T> collection, Func<T, string?> objectFormatter, string separator)
    {
        ArgumentNullException.ThrowIfNull(collection);
        ArgumentNullException.ThrowIfNull(objectFormatter);

        return HumanizeDisplayStrings(collection, objectFormatter, separator);
    }

    /// <summary>
    /// Formats with an object-returning formatter, converting via .ToString().
    /// </summary>
    public string Humanize<T>(
        IEnumerable<T> collection, Func<T, object?> objectFormatter, string separator)
    {
        ArgumentNullException.ThrowIfNull(collection);
        ArgumentNullException.ThrowIfNull(objectFormatter);

        // Single pass: combine the object formatter and ToString into one projection
        return HumanizeDisplayStrings(collection, item => objectFormatter(item)?.ToString(), separator);
    }

    private string HumanizeDisplayStrings<T>(
        IEnumerable<T> source, Func<T, string?> formatter, string separator)
    {
        // Single-pass collection into a list, applying format + trim inline
        // to avoid chained Select/Where/ToArray enumerator allocations.
        var items = new List<string>();
        foreach (var element in source)
        {
            var item = formatter(element);
            if (item != null)
            {
                var trimmed = item.Trim();
                if (trimmed.Length > 0)
                {
                    items.Add(trimmed);
                }
            }
        }

        if (items.Count == 0)
        {
            return string.Empty;
        }

        if (items.Count == 1)
        {
            return items[0];
        }

        var allButLast = string.Join(separator, items.Take(items.Count - 1));
        return $"{allButLast} and {items[^1]}";
    }
}

